option.value:
/* ── Layout ──────────────────────────────────────────────────────────────────── */
#history-root {
  display: grid;
  grid-template-columns: 320px 1fr;
  height: calc(100vh - 46px);
  overflow: hidden;
}

/* ── Nav link ────────────────────────────────────────────────────────────────── */
.topbar-nav { display: flex; align-items: center; }
.nav-link {
  font-size: 11px; font-weight: 700; letter-spacing: 1.5px;
  color: var(--muted);
  text-decoration: none;
  padding: 4px 10px;
  border: 1px solid var(--border);
  border-radius: 3px;
  transition: color .2s, border-color .2s;
}
.nav-link:hover { color: var(--text); border-color: var(--muted); }

/* ── Session list panel ──────────────────────────────────────────────────────── */
#session-list-panel {
  background: var(--surface);
  border-right: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.h-panel-header {
  padding: 16px;
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}
.h-panel-title { font-size: 11px; font-weight: 700; letter-spacing: 2.5px; text-transform: uppercase; color: var(--muted); }
.h-panel-sub   { font-size: 11px; color: var(--muted); margin-top: 4px; }

/* Records strip */
.records-strip {
  padding: 12px 16px;
  border-bottom: 1px solid var(--border);
  background: rgba(225,6,0,.04);
  flex-shrink: 0;
}
.records-strip.hidden { display: none; }
.records-title { font-size: 9px; font-weight: 700; letter-spacing: 2px; color: var(--accent); margin-bottom: 8px; }
.record-row {
  display: flex; justify-content: space-between; align-items: baseline;
  padding: 3px 0;
  border-bottom: 1px solid var(--border);
  font-size: 11px;
}
.record-row:last-child { border: none; }
.record-track { color: var(--muted); }
.record-time  { font-family: var(--font-mono), monospace; font-weight: 600; color: var(--yellow); }
.record-type  { font-size: 9px; color: var(--muted); letter-spacing: 1px; }

/* Session list */
#session-list {
  flex: 1;
  overflow-y: auto;
  padding: 8px;
}
#session-list::-webkit-scrollbar { width: 4px; }
#session-list::-webkit-scrollbar-track { background: transparent; }
#session-list::-webkit-scrollbar-thumb { background: var(--border); border-radius: 2px; }

.session-card {
  padding: 12px;
  border: 1px solid var(--border);
  border-radius: 5px;
  margin-bottom: 6px;
  cursor: pointer;
  transition: border-color .15s, background .15s;
  background: var(--panel);
}
.session-card:hover  { border-color: var(--muted); background: #1a1a24; }
.session-card.active { border-color: var(--accent); background: rgba(225,6,0,.05); }

.sc-top { display: flex; justify-content: space-between; align-items: flex-start; }
.sc-track {
  font-size: 13px; font-weight: 700;
  color: var(--text); line-height: 1.2;
}
.sc-type {
  font-size: 9px; font-weight: 700; letter-spacing: 1.5px;
  padding: 2px 6px; border-radius: 2px;
  border: 1px solid var(--border);
  color: var(--muted);
  white-space: nowrap;
}
.sc-type.race     { color: var(--accent); border-color: var(--accent); }
.sc-type.quali    { color: var(--yellow); border-color: var(--yellow); }
.sc-type.practice { color: var(--green);  border-color: var(--green);  }
.sc-type.sprint   { color: var(--orange); border-color: var(--orange); }

.sc-meta {
  display: flex; gap: 10px;
  margin-top: 6px; font-size: 10px; color: var(--muted);
}
.sc-best {
  font-family: var(--font-mono), monospace;
  font-size: 11px; font-weight: 600;
  color: var(--yellow);
  margin-top: 4px;
}

/* ── Session detail panel ────────────────────────────────────────────────────── */
#session-detail {
  overflow-y: auto;
  padding: 20px;
}
#session-detail::-webkit-scrollbar { width: 4px; }
#session-detail::-webkit-scrollbar-thumb { background: var(--border); border-radius: 2px; }

/* Summary cards row */
.summary-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
  gap: 10px;
  margin-bottom: 20px;
}
.summary-card {
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: 5px;
  padding: 12px;
}
.sc-label { font-size: 9px; font-weight: 700; letter-spacing: 2px; text-transform: uppercase; color: var(--muted); }
.sc-value { font-family: var(--font-mono), monospace; font-size: 20px; font-weight: 600; margin-top: 4px; color: var(--white); }
.sc-value.accent  { color: var(--accent);  }
.sc-value.green   { color: var(--green);   }
.sc-value.yellow  { color: var(--yellow);  }
.sc-value.blue    { color: var(--blue);    }
.sc-value.purple  { color: #bb00ff;        }
.sc-sub { font-size: 10px; color: var(--muted); margin-top: 2px; }

/* Sector bests row */
.sector-bests {
  display: flex; gap: 8px;
  margin-bottom: 20px;
}
.sector-best-card {
  flex: 1;
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: 5px;
  padding: 10px;
  text-align: center;
}
.sb-label { font-size: 9px; color: var(--muted); letter-spacing: 2px; font-weight: 700; }
.sb-time  { font-family: var(--font-mono), monospace; font-size: 16px; font-weight: 600; color: #bb00ff; margin-top: 4px; }
.sb-note  { font-size: 9px; color: var(--muted); margin-top: 2px; }

/* Lap table */
.section-title {
  font-size: 9px; font-weight: 700; letter-spacing: 2.5px;
  text-transform: uppercase; color: var(--muted);
  margin-bottom: 10px;
  display: flex; align-items: center; gap: 8px;
}
.section-title span { color: var(--accent); }

.lap-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 12px;
}
.lap-table th {
  text-align: left;
  font-size: 9px; font-weight: 700; letter-spacing: 2px;
  color: var(--muted); text-transform: uppercase;
  padding: 6px 10px;
  border-bottom: 1px solid var(--border);
}
.lap-table td {
  padding: 8px 10px;
  border-bottom: 1px solid var(--border);
  font-family: var(--font-mono), monospace;
  color: var(--text);
}
.lap-table tr:last-child td { border-bottom: none; }
.lap-table tr:hover td { background: rgba(255,255,255,.02); }

/* Fastest lap row */
.lap-table tr.fastest td { background: rgba(187,0,255,.05); }
.lap-table tr.fastest td:first-child { border-left: 2px solid #bb00ff; }

/* Invalid lap */
.lap-table tr.invalid td { opacity: .45; }

/* Lap number */
td.lap-num { color: var(--muted); font-size: 11px; }

/* Lap time */
td.lap-time { font-size: 14px; font-weight: 600; }
td.lap-time.fastest-cell { color: #bb00ff; }

/* Sector times */
td.sector { font-size: 11px; color: var(--muted); }

/* Tyre badge */
.tyre-badge {
  display: inline-block;
  padding: 1px 6px; border-radius: 2px;
  font-size: 10px; font-weight: 700;
  color: #111;
  font-family: var(--font-main);
}
.tyre-badge.Soft   { background: var(--soft-c); }
.tyre-badge.Medium { background: var(--medium-c); }
.tyre-badge.Hard   { background: var(--hard-c); }
.tyre-badge.Inter  { background: var(--inter-c); }
.tyre-badge.Wet    { background: var(--wet-c); }
.tyre-badge.unknown { background: var(--border); color: var(--muted); }

/* Validity / pit */
td.flags { color: var(--muted); font-size: 11px; letter-spacing: 1px; }

/* Delta column */
td.delta { font-size: 11px; }
td.delta.positive { color: var(--accent); }
td.delta.negative { color: var(--green);  }

/* Bar chart strip */
.lap-chart {
  margin-bottom: 20px;
}
.chart-bars {
  display: flex;
  align-items: flex-end;
  gap: 3px;
  height: 60px;
  padding: 0 2px;
}
.chart-bar {
  flex: 1;
  border-radius: 2px 2px 0 0;
  background: var(--border);
  min-width: 4px;
  cursor: pointer;
  transition: background .1s;
  position: relative;
}
.chart-bar:hover { background: var(--muted); }
.chart-bar.fastest-bar { background: #bb00ff; }
.chart-bar.invalid-bar { background: #2a1a1a; }
.chart-bar .bar-tip {
  display: none;
  position: absolute;
  bottom: calc(100% + 4px);
  left: 50%; transform: translateX(-50%);
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 3px;
  padding: 4px 8px;
  font-size: 10px;
  font-family: var(--font-mono);
  white-space: nowrap;
  z-index: 10;
  color: var(--text);
}
.chart-bar:hover .bar-tip { display: block; }

/* Empty / loading states */
.empty-state {
  color: var(--muted);
  font-size: 13px;
  padding: 20px;
  letter-spacing: 0.5px;
}
.empty-state.centered {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100%;
  gap: 12px;
}
.empty-icon { font-size: 36px; opacity: .3; }

